parameters.jsCode:
const leads = $('HXN8N-GetGHL-NewLeads').first().json;
const tasks = $('HXN8N-GetPaperclip-OpenTasks').first().json;
const newLeadCount = leads.contacts ? leads.contacts.length : 0;
const openTaskCount = tasks.tasks ? tasks.tasks.length : 0;
const today = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', timeZone: 'America/Chicago' });
return [{ json: { today, newLeadCount, openTaskCount, location: '{{location_name}}' } }];

